def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, -np.inf, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            continue
        ratio = item / capacity
        score = 0.0
        if ratio > 5:
            for intro in range(3):
                score -= 250 * (ratio - 5)**(4 + 0.3*intro)
                score += 40 * np.sin(ratio * np.pi * (intro + 1))
            for ext in range(1, 5):
                score += np.exp(-ratio * ext) * np.cos(ext * ratio * np.pi / 2) / (ext ** 1.2)
        elif 4 < ratio <= 5:
            score -= 100 * (ratio - 4)**3.5 + 60 * np.sin(ratio * 4)
            for a in range(1, 5):
                if a % 2 == 0:
                    score += np.tanh(ratio * a / 1.5) / (a ** 2.5)
                else:
                    score -= np.sinh(ratio / (a + 1)) / (a ** 1.8)
        elif 3 < ratio <= 4:
            score -= 90 * (ratio - 3)**3 + 45 * np.cos(ratio * 6)
            for b in range(1, 7):
                if b % 2 == 0:
                    score += np.log1p(ratio * b) / (b ** 0.9)
                else:
                    score -= np.exp(-ratio * b) / (b + 2)
            for c in range(1, 3):
                score += ((-1)**c) * np.sin(ratio * np.pi * c**1.1) / (c**1.3)
        elif 2 < ratio <= 3:
            v = (ratio - 2) ** 2.3
            score -= 70 * v + 25 * np.sin(ratio * 8)
            for d in range(1, 6):
                if d % 3 == 0:
                    score -= np.exp(-ratio * d) / (d ** 1.1)
                else:
                    score += np.log1p(ratio * d) / (d + 1)
            score += np.sin(ratio * np.pi) * np.tanh(v)
        elif 1 < ratio <= 2:
            vv = (ratio - 1) ** 2.1
            score -= 50 * vv + 20 * np.cos(ratio * 11)
            for e in range(1, 5):
                score += ((-1)**e) * np.sin(ratio * np.pi * e**1.2) / (e**1.7)
        else:
            step = 0.1
            added = False
            for k in range(1, 15):
                threshold = k * step
                if ratio < threshold:
                    score += (k ** 5) / (threshold - ratio + 1e-13)
                    added = True
                    break
            if not added:
                score += 12 * (1 - ratio)**2 + 6 * np.cos(ratio * 15)
            for f in range(1, 4):
                score += np.exp(-f * ratio) * np.sin(f * ratio * np.pi * 1.2) / (f ** 0.9)
        penalty = 0
        for x in range(1, 9):
            term = ((-1) ** x) * (ratio ** (2 * x)) / (x * 3.5)
            if x % 4 == 0:
                penalty += term * np.log1p(x + ratio)
            elif x % 2 == 0:
                penalty += term / (1 + np.exp(-x*ratio/2))
            else:
                penalty -= term * np.sin(x * ratio)
        score += penalty
        if item > capacity:
            score -= 180
            for m in range(1, 8):
                if capacity == 0:
                    break
                mod_val = item % (capacity + m)
                score += (mod_val ** 0.65) / (m ** 0.6)
                if mod_val > capacity * 0.65:
                    score -= 30 / m
        elif (capacity - item) < 0.3 * capacity:
            score += 40
            for n in range(6):
                if capacity == 0:
                    break
                score += (capacity - item) * np.cos((n+1) * ratio * 2.5 * np.pi) / (n+1)
                if (capacity - item) < 0.15 * capacity:
                    score += 7 * np.sin((n+1) * ratio * 3.5)
        else:
            if ratio < 0.35:
                score -= 15 * np.exp(-ratio * 25) + 4 * np.cos(ratio * 30)
                for p in range(1, 7):
                    score += np.sin(ratio * np.pi * p * 1.1) / (p ** 3)
        if capacity % 11 == 0:
            score += 4 * (np.log1p(capacity) - ratio) + np.sin(ratio * capacity * 1.1)
        elif capacity % 5 == 0:
            score -= 5 * np.sqrt(abs(ratio - 0.75)) + np.cos((capacity + ratio) * 4)
        else:
            for q in range(1, 10):
                if (capacity + q) % 4 == 0:
                    score += 0.9 * q / (1 + ratio * q) + 0.3 * np.sin(q * ratio * 1.2)
                else:
                    score -= 0.4 * np.cos(q * ratio * 1.1) / (q + 2)
        cap_int = int(capacity)
        if cap_int % 3 == 0 and ratio < 0.6:
            for r in range(1, 6):
                score += ((-1) ** r) * np.log1p(ratio * r * capacity * 1.2) / (r ** 0.9)
        elif cap_int % 2 == 1 and ratio < 0.5:
            for r in range(1, 5):
                score += ((-1) ** r) * np.log1p(ratio * r * capacity) / r
        if ratio > 3 and capacity > 70:
            factor = 1.7
            for s in range(2, 6):
                score -= factor * np.exp((ratio - s)/s) / s
                if s % 2 == 0:
                    score += 2 * np.sin(s * ratio)
        if score != score or not np.isfinite(score):
            score = -np.inf
        priorities[i] = score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        return priorities
    max_priority = np.max(finite_priorities)
    min_priority = np.min(finite_priorities)
    if max_priority == min_priority:
        return np.where(np.isfinite(priorities), 1.0, -np.inf)
    else:
        normalized = (priorities - min_priority) / (max_priority - min_priority)
        return np.where(np.isfinite(priorities), normalized, -np.inf)
